    "skill_name": "Heat & Cooking Control",
    "category": "Culinary Technique",
    "cluster": "Cooking Methods",
    "skill_description": "Understanding and application of dry and moist heat cooking methods to achieve desired results.",
    "levels": [
      {
        "level": 1,
        "level_name": "Beginner",
        "level_description": "Recognizes basic dry and moist heat methods and follows established recipe procedures for temperature and timing. Produces inconsistent doneness levels and requires guidance on adjusting heat based on ingredient behavior."
      },
      {
        "level": 2,
        "level_name": "Proficient",
